**JavaScript Client-Side Validation**

```javascript
// script.js
const form = document.getElementById('membership-form');
const errorMessage = document.getElementById('error-message');

form.addEventListener('submit', (e) => {
    e.preventDefault();
    const membershipId = document.getElementById('membership-id').value.trim();
    const regex = /^[a-zA-Z0-9]{6,12}$/; // allow 6-12 alphanumeric characters

    if (membershipId === '') {
        errorMessage.textContent = 'Membership ID is required.';
    } else if (!regex.test(membershipId)) {
        errorMessage.textContent = 'Membership ID must be 6-12 alphanumeric characters.';
    } else {
        // send the form data to the server for further validation and processing
        // you can use AJAX or fetch API for this
        fetch('/process-membership-id', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ membershipId })
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                console.log('Membership ID validated successfully.');
                // redirect to a success page or display a success message
            } else {
                console.error('Membership ID validation failed.');
                // display an error message or redirect to an error page
            }
        })
        .catch(error => console.error('Error:', error));
    }
});
```

**Server-Side Validation and Data Protection**

For server-side validation and data protection, you'll need to use a server-side programming language like PHP, Python, or Ruby. Here's an example using PHP:

```php
// process-membership-id.php
<?php
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $membershipId = $_POST['membership-id'];

    // validate the membership ID
    if (strlen($membershipId) < 6 || strlen($membershipId) > 12) {
        echo json_encode(['success' => false, 'message' => 'Membership ID must be 6-12 characters long.']);
    } elseif (!ctype_alnum($membershipId)) {
        echo json_encode(['success' => false, 'message' => 'Membership ID must be alphanumeric.']);
    } else {
        // store the membership ID in a secure database or file
        // you can use a library like PDO or MySQLi for database interactions
        $db = new PDO('mysql:host=localhost;dbname=memberships', 'username', 'password');
        $stmt = $db->prepare('INSERT INTO memberships (membership_id) VALUES (:membership_id)');
        $stmt->bindParam(':membership_id', $membershipId);
        $stmt->execute();

        echo json_encode(['success' => true, 'message' => 'Membership ID validated successfully.']);
    }
} else {
    echo json_encode(['success' => false, 'message' => 'Invalid request method.']);
}
?>
```

Remember to replace the placeholders with your actual database credentials and file paths.

